// code → entry lookup
export const RESULT_BY_CODE: Map<number, ResultClassificationEntry> = new Map(
  RESULT_CLASSIFICATION.map((e) => [e.code, e])
);

// group → entries lookup (for 묶음별 합산)
export const RESULT_BY_GROUP: Map<string, ResultClassificationEntry[]> = (() => {
  const map = new Map<string, ResultClassificationEntry[]>();
  for (const e of RESULT_CLASSIFICATION) {
    if (!e.group) continue;
    const list = map.get(e.group) ?? [];
    list.push(e);
    map.set(e.group, list);
  }
  return map;
})();
